<template><view class="page"><AppCard title="蓝牙一键配网"><button class="btn" @click="discover">搜索庆喜儿设备</button><view v-for="d in devices" :key="d.deviceId" class="list-item" @click="selected=d.deviceId">{{d.name}} <text v-if="selected===d.deviceId">✓</text></view><input class="input" v-model="ssid" placeholder="Wi-Fi 名称"/><input class="input" v-model="password" password placeholder="Wi-Fi 密码（至少8位）"/><button class="btn" @click="provision">开始配网</button><view class="subtitle">状态：{{service.state}} {{service.error}}</view></AppCard></view></template>
<script setup lang="ts">import{ref}from'vue';import AppCard from'@/components/AppCard.vue';import{ProvisioningService}from'@/services/ble';import{qingxierApi}from'@/services/api';const service=new ProvisioningService();const devices=ref<any[]>([]),selected=ref(''),ssid=ref(''),password=ref('');async function discover(){devices.value=await service.discover();}async function provision(){try{const ticket=await qingxierApi.bindTicket({deviceSn:'SN001',model:'QXR-S3',blePublicKey:'temporary-public-key'});const ok=await service.provision(selected.value,ssid.value,password.value,ticket.ticket);if(ok){await qingxierApi.bindDevice({ticket:ticket.ticket,deviceId:ticket.deviceId,bindProof:'bind-proof-123'});uni.showToast({title:'配网成功'});}}catch(e:any){uni.showToast({title:e.message,icon:'none'});}}</script>
